import{_ as t,c as o,o as i,ag as a}from"./chunks/framework.DD2hp6gW.js";const u=JSON.parse('{"title":"Checkboxes Field","description":"","frontmatter":{},"headers":[],"relativePath":"fields/checkbox.md","filePath":"fields/checkbox.md","lastUpdated":null}'),s={name:"fields/checkbox.md"};function l(n,e,r,d,c,h){return i(),o("div",null,e[0]||(e[0]=[a('<h1 id="checkboxes-field" tabindex="-1">Checkboxes Field <a class="header-anchor" href="#checkboxes-field" aria-label="Permalink to &quot;Checkboxes Field&quot;">​</a></h1><p>The <strong>Checkbox</strong> field allows customers to select one or <strong>multiple</strong> options from a predefined list. Each checked option&#39;s price is individually added to the product total, making this field ideal for add-on bundles.</p><h2 id="common-use-cases" tabindex="-1">Common Use Cases <a class="header-anchor" href="#common-use-cases" aria-label="Permalink to &quot;Common Use Cases&quot;">​</a></h2><ul><li>Selecting extra toppings (e.g., Cheese, Pepperoni, Mushrooms)</li><li>Choosing multiple add-on accessories (e.g., Cable, Case, Screen Protector)</li><li>Opting into multiple services (e.g., Gift Wrapping + Express Processing + Insurance)</li><li>Multi-select feature upgrades</li></ul><h2 id="field-settings" tabindex="-1">Field Settings <a class="header-anchor" href="#field-settings" aria-label="Permalink to &quot;Field Settings&quot;">​</a></h2><p>When you add a Checkbox field and expand it in the builder, the following settings are available:</p><h3 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The title displayed above the checkbox group (e.g., &quot;Select Your Toppings&quot;).</td></tr><tr><td style="text-align:left;"><strong>Description</strong></td><td style="text-align:left;">Optional help text shown below the field (e.g., &quot;Choose as many as you like&quot;).</td></tr><tr><td style="text-align:left;"><strong>Required</strong></td><td style="text-align:left;">When checked, the customer must select <strong>at least one</strong> checkbox option before adding the product to the cart.</td></tr></tbody></table><h3 id="choices-options" tabindex="-1">Choices (Options) <a class="header-anchor" href="#choices-options" aria-label="Permalink to &quot;Choices (Options)&quot;">​</a></h3><p>You must define at least one choice. Each choice has the following columns:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Column</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Label</strong></td><td style="text-align:left;">The text displayed next to the checkbox (e.g., &quot;Extra Cheese&quot;). The <strong>Value</strong> is automatically generated from the label.</td></tr><tr><td style="text-align:left;"><strong>Price</strong></td><td style="text-align:left;">The numeric amount to add to the product price when this specific checkbox is ticked. Only visible when Price Type is not &quot;No Price&quot;.</td></tr><tr><td style="text-align:left;"><strong>Price Type</strong></td><td style="text-align:left;">How this choice affects pricing. Options: <strong>No Price</strong>, <strong>Flat Fee</strong>, <strong>Percentage of Base</strong>, or <strong>Formula</strong>. Each choice can have its own independent price type.</td></tr><tr><td style="text-align:left;"><strong>Weight</strong></td><td style="text-align:left;">Additional shipping weight to add when this choice is selected.</td></tr></tbody></table><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Because multiple checkboxes can be selected simultaneously, the <strong>total addon price</strong> is the sum of all individually checked options. For example, if &quot;Extra Cheese&quot; is $2.00 and &quot;Pepperoni&quot; is $3.00, and both are checked, the total addon cost is $5.00.</p></div><p>You can add new choices using the <strong>+ Add Choice</strong> button and remove them using the trash icon.</p><h2 id="conditional-logic" tabindex="-1">Conditional Logic <a class="header-anchor" href="#conditional-logic" aria-label="Permalink to &quot;Conditional Logic&quot;">​</a></h2><p>You can show or hide this field based on the value of another field in the same group. For example, show a &quot;Choose Your Toppings&quot; checkbox group only when the customer selects &quot;Pizza&quot; from a product type dropdown.</p><p>For full details on setting up rules, see the <a href="./../conditional-logic.html">Conditional Logic</a> page.</p>',16)]))}const p=t(s,[["render",l]]);export{u as __pageData,p as default};
